const AWS = require('aws-sdk');
const s3 = new AWS.S3();
const { v4: uuidv4 } = require('uuid');

exports.handler = async (event) => {
    try {
        // Validate S3 event
        if (!event.Records || event.Records.length === 0) {
            throw new Error('No S3 records found');
        }

        const record = event.Records[0];
        const bucket = record.s3.bucket.name;
        const key = decodeURIComponent(record.s3.object.key.replace(/\+/g, ' '));
        
        // Validate input file
        if (!key || key.endsWith('/')) {
            throw new Error('Invalid file key');
        }

        // Read file from S3
        const fileData = await s3.getObject({
            Bucket: bucket,
            Key: key
        }).promise();

        // Process file content
        const processedData = await processFileContent(fileData.Body);

        // Generate output key using original filename
        const outputKey = key.replace(/\.[^/.]+$/, '') + '_processed.txt';

        // Save processed file to S3
        await s3.putObject({
            Bucket: bucket,
            Key: outputKey,
            Body: processedData,
            ContentType: 'text/plain'
        }).promise();

        return {
            statusCode: 200,
            body: JSON.stringify({
                message: 'File processed successfully',
                inputKey: key,
                outputKey: outputKey
            })
        };
    } catch (error) {
        console.error('Error processing file:', error);
        throw error;
    }
};

async function processFileContent(content) {
    // Example processing - replace with actual logic
    const text = content.toString('utf-8');
    
    // Add security checks
    if (text.length > 10 * 1024 * 1024) { // 10MB limit
        throw new Error('File too large');
    }
    
    // Process content (example: convert to uppercase)
    return text.toUpperCase();
}